1	//! Producing endpoint: [`Producer`] reserves the next free
2	//! slot, the [`WriteSlot`] guard writes it in place and
3	//! commits.
4	
5	use core::marker::PhantomData;
6	use core::ops::{Deref, DerefMut};
7	use core::sync::atomic::{AtomicU32, Ordering};
8	use zerocopy::{FromBytes, IntoBytes, KnownLayout};
9	
10	use crate::{Header, USER_WORDS, check_type, slot_ptr};
11	
12	/// `reserve_slot` failed: every slot holds an
13	/// uncommitted-or-unread message.
14	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
15	pub struct Full;
16	
17	/// The producing endpoint: `reserve_slot`, write in place,
18	/// `commit`.
19	pub struct Producer<'a> {
20	    /// The ring's control block.
21	    header: &'a Header,
22	    /// Base of the slot array.
23	    slots: *mut u8,
24	    /// Geometry snapshot (see [`Ring`](crate::Ring)).
25	    slot_size: u32,
26	    /// Geometry snapshot (see [`Ring`](crate::Ring)).
27	    capacity: u32,
28	    /// Slot-position mask (`capacity - 1`).
29	    mask: u32,
30	    _region: PhantomData<&'a [u8]>,
31	}
32	
33	// SAFETY: the handle owns the producer role; the shared state it
34	// touches (indices) is atomic, and slot writes are handed off
35	// with Release/Acquire ordering.
36	unsafe impl Send for Producer<'_> {}
37	
38	impl<'a> Producer<'a> {
39	    /// Build the handle from [`Ring::split`](crate::Ring::split)'s
40	    /// geometry snapshot.
41	    pub(crate) fn new(
42	        header: &'a Header,
43	        slots: *mut u8,
44	        slot_size: u32,
45	        capacity: u32,
46	        mask: u32,
47	    ) -> Self {
48	        Producer {
49	            header,
50	            slots,
51	            slot_size,
52	            capacity,
53	            mask,
54	            _region: PhantomData,
55	        }
56	    }
57	
58	    /// The header's app-owned scratch line: zeroed at init,
59	    /// never touched by the crate again.
60	    ///
61	    /// - Shared with the peer: treat contents as untrusted
62	    ///   data — store values, never addresses to dereference.
63	    /// - See the design doc's "Blocking and user words" for
64	    ///   the wakeup-protocol contract it exists to host.
65	    pub fn user(&self) -> &[AtomicU32; USER_WORDS] {
66	        &self.header.user
67	    }
68	
69	    /// Reserve the next free slot as a `&mut T`, or [`Full`].
70	    ///
71	    /// - Only one slot may be reserved at a time: the guard
72	    ///   holds the `&mut Producer` borrow, so a second
73	    ///   `reserve_slot` before the guard is dropped or
74	    ///   committed does not compile.
75	    /// - Dropping the guard without [`WriteSlot::commit`]
76	    ///   abandons the reservation (nothing published).
77	    pub fn reserve_slot<T>(&mut self) -> Result<WriteSlot<'_, T>, Full>
78	    where
79	        T: FromBytes + IntoBytes + KnownLayout,
80	    {
81	        check_type::<T>(self.slot_size);
82	        let p = self.header.producer_idx.load(Ordering::Relaxed);
83	        let c = self.header.consumer_idx.load(Ordering::Acquire);
84	        // `>=`, not `==`: a peer-corrupted consumer_idx makes
85	        // occupancy look huge — fail Full, never hand out a
86	        // slot the protocol doesn't own.
87	        if p.wrapping_sub(c) >= self.capacity {
88	            return Err(Full);
89	        }
90	        // Raw pointer, not `&mut T`: a reference field would be
91	        // argument-protected for the whole `commit(self)` call,
92	        // while commit's Release store lets the consumer read
93	        // the slot inside that window — UB (Miri-verified).
94	        // Deref mints short-lived references instead.
95	        let msg = slot_ptr(self.slots, p, self.mask, self.slot_size) as *mut T;
96	        Ok(WriteSlot {
97	            header: self.header,
98	            msg,
99	            next_idx: p.wrapping_add(1),
100	            _slot: PhantomData,
101	        })
102	    }
103	
104	    /// [`reserve_slot`](Producer::reserve_slot) with an
105	    /// injected wait policy: retry until a slot frees up or
106	    /// the policy gives up.
107	    ///
108	    /// - `on_full` is called after each failed attempt with
109	    ///   the attempt count (0-based, saturating); returning
110	    ///   `false` gives up → `Err(Full)`.
111	    /// - The wait loop is the reservation itself (the guard
112	    ///   borrows the endpoint, so retrying a `reserve_slot`
113	    ///   call could not return it): `producer_idx` is ours
114	    ///   and loaded once; only `consumer_idx` is re-read per
115	    ///   attempt, so the no-wait fast path does exactly the
116	    ///   loads `reserve_slot` does.
117	    /// - See [`policy`](crate::policy) for shipped policies
118	    ///   and the composition model.
119	    pub fn reserve_slot_with<T>(
120	        &mut self,
121	        mut on_full: impl FnMut(u32) -> bool,
122	    ) -> Result<WriteSlot<'_, T>, Full>
123	    where
124	        T: FromBytes + IntoBytes + KnownLayout,
125	    {
126	        check_type::<T>(self.slot_size);
127	        // Ours alone: no peer moves it, load once.
128	        let p = self.header.producer_idx.load(Ordering::Relaxed);
129	        let mut attempt = 0u32;
130	        loop {
131	            // Same load + `>=` occupancy check as
132	            // reserve_slot (see there for the corruption
133	            // rationale).
134	            let c = self.header.consumer_idx.load(Ordering::Acquire);
135	            if p.wrapping_sub(c) < self.capacity {
136	                break;
137	            }
138	            if !on_full(attempt) {
139	                return Err(Full);
140	            }
141	            attempt = attempt.saturating_add(1);
142	        }
143	        // Raw pointer, not `&mut T` — see reserve_slot.
144	        let msg = slot_ptr(self.slots, p, self.mask, self.slot_size) as *mut T;
145	        Ok(WriteSlot {
146	            header: self.header,
147	            msg,
148	            next_idx: p.wrapping_add(1),
149	            _slot: PhantomData,
150	        })
151	    }
152	
153	    /// [`reserve_slot`](Producer::reserve_slot), spinning
154	    /// until a slot is available —
155	    /// [`reserve_slot_with`](Producer::reserve_slot_with)
